mapper.select:
SELECT CUSTOMER_ID AS customerId, CUSTOMER_CODE AS customerCode, CUSTOMER_NAME AS customerName, CUSTOMER_TYPE AS customerType, BUSINESS_NO AS businessNo, CEO_NAME AS ceoName, PHONE AS phone, EMAIL AS email, ADDRESS AS address, MANAGER_NAME AS managerName, MANAGER_PHONE AS managerPhone, USE_YN AS useYn, REMARK AS remark, CREATED_AT AS createdAt, UPDATED_AT AS updatedAt FROM CUSTOMERS WHERE 1=1
AND CUSTOMER_CODE LIKE CONCAT('%', #{customerCode}, '%')
AND CUSTOMER_NAME LIKE CONCAT('%', #{customerName}, '%')
AND CUSTOMER_TYPE = #{customerType}
AND USE_YN = #{useYn}
ORDER BY CUSTOMER_ID DESC
